import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";
const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI", "TALEP", "TEDARİK", "VERİLEMEYEN", "TED. %",
    "SPOT", "FİLO", "TESİSTE", "GELECEK", "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER", "HEDEF ALTI SEFER", "HEDEF SEFER", "HEDEFSİZ SEFER",
    "ODAK_TALEP", "ODAK_TEDARİK", "ODAK_VERİLEMEYEN"
];

const ALLOWED_PROJECTS = new Set([
    "BUNGE LÜLEBURGAZ FTL", "REKA FTL", "EKSUN GIDA FTL", "SARUHAN FTL",
    "PEPSİ FTL", "MUTLU MAKARNA SPOT FTL", "TEKİRDAĞ UN FTL", "AYDINLI MODA FTL",
    "ADKOTURK FTL", "ADKOTURK FTL ENERJİ İÇECEĞİ", "SGS FTL", "BSH FTL",
    "ALTERNA GIDA FTL", "DERYA OFİS FTL", "SAPRO FTL", "MARMARA CAM FTL",
    "FAKİR FTL", "MODERN KARTON FTL", "KÜÇÜKBAY FTL"
]);

const projectMergeMap = {
    "BUNGE LÜLEBURGAZ FTL": ["BUNGE LÜLEBURGAZ FTL", "BUNGE DİLOVASI-REYSAŞ", "BUNGE PALET"],
    "MODERN KARTON FTL": ["MODERN KARTON-PACKON", "MODERN KARTON-NİŞASTA"]
};
const [odakAllData, setOdakAllData] = useState([]);


function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization:
                            "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                console.log("📦 ODAK API TÜM PROJECTNAME’LERİ:", [
                    ...new Set(items.map((i) => i.ProjectName)),
                ]);

                const projectMap = new Map();

                items.forEach((item) => {
                    if (
                        item.OrderStatu === 200 ||
                        !item.TMSVehicleRequestDocumentNo ||
                        !item.ProjectName
                    ) {
                        return;
                    }

                    const project = item.ProjectName;
                    const despatch = !!item.TMSDespatchDocumentNo;
                    const vehicleNo = item.TMSVehicleRequestDocumentNo;
                    const key = `${project}-${vehicleNo}`;

                    if (!projectMap.has(project)) {
                        projectMap.set(project, {
                            ProjectName: project,
                            Talep: 0,
                            Tedarik: 0,
                            Verilemeyen: 0,
                            _seenKeys: new Set(),
                        });
                    }

                    const projData = projectMap.get(project);
                    if (!projData._seenKeys.has(key)) {
                        projData._seenKeys.add(key);
                        projData.Talep += 1;
                        if (despatch) projData.Tedarik += 1;
                        else projData.Verilemeyen += 1;
                    }
                });

                const finalData = Array.from(projectMap.values()).map((p) => {
                    delete p._seenKeys;
                    return p;
                });

                setOdakAllData(finalData); // tümü tutulur
                setOdakData(finalData.filter(p => ALLOWED_PROJECTS.has(p.ProjectName))); // sadece izinli olan tabloya aktarılır
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);


    useEffect(() => {
        if (data.length === 0 || odakData.length === 0) return;

        console.log("📦 ODAK API'DEN GELEN PROJECTNAME LİSTESİ:");
        console.log(odakData.map((o) => o.ProjectName));

        const header = data[0];
        const rows = data.slice(1);

        const updatedRows = rows.map((row) => ({
            ...row,
            ODAK_TALEP: 0,
            ODAK_TEDARİK: 0,
            ODAK_VERİLEMEYEN: 0,
        }));

        odakData.forEach((odak) => {
            const groupList = projectMergeMap[odak.ProjectName] || [odak.ProjectName];

            for (let i = 0; i < updatedRows.length; i++) {
                const projeAdi = updatedRows[i]["PROJE ADI"]?.trim();
                if (groupList.includes(projeAdi)) {
                    updatedRows[i]["ODAK_TALEP"] = odak.Talep ?? 0;
                    updatedRows[i]["ODAK_TEDARİK"] = odak.Tedarik ?? 0;
                    updatedRows[i]["ODAK_VERİLEMEYEN"] = odak.Verilemeyen ?? 0;
                    break;
                }
            }
        });

        const mergedData = [header, ...updatedRows];
        setData(mergedData);
    }, [odakData]);



    return (
        <div className="app-container">
            <div className="section">
                <h2>🟢 Supabase + Odak Verileri</h2>
                {data.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {columnOrder.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {(() => {
                                    const renderedRows = new Set();
                                    return data.slice(1).flatMap((row, idx) => {
                                        const projeAdi = row["PROJE ADI"]?.trim();
                                        const anaProje = Object.entries(projectMergeMap).find(([_, group]) =>
                                            group.includes(projeAdi)
                                        )?.[0];

                                        if (anaProje && renderedRows.has(projeAdi)) return [];

                                        const groupRows = anaProje
                                            ? data.slice(1).filter((r) =>
                                                projectMergeMap[anaProje].includes(r["PROJE ADI"]?.trim())
                                            )
                                            : [row];

                                        groupRows.forEach((r) =>
                                            renderedRows.add(r["PROJE ADI"]?.trim())
                                        );

                                        return groupRows.map((groupRow, groupIdx) => (
                                            <tr key={`${groupRow["PROJE ADI"]}-${groupIdx}`}>
                                                {columnOrder.map((col, colIdx) => {
                                                    const value = groupRow[col];
                                                    let displayValue = value;
                                                    let style = {};

                                                    if (col === "TED. %") {
                                                        const parsed = parseFloat(value);
                                                        if (!isNaN(parsed)) {
                                                            const percentage = Math.round(parsed * 100);
                                                            displayValue = `%${percentage}`;
                                                            style = {
                                                                color:
                                                                    percentage < 70 ? "#e74c3c" :
                                                                        percentage < 90 ? "#f39c12" :
                                                                            "#27ae60",
                                                                fontWeight: "bold",
                                                            };
                                                        }
                                                    }

                                                    if (
                                                        col === "HEDEF ÜSTÜ SEFER" ||
                                                        col === "HEDEF ALTI SEFER" ||
                                                        col === "HEDEF SEFER"
                                                    ) {
                                                        const parsed = parseFloat(value);
                                                        if (!isNaN(parsed)) {
                                                            displayValue = `${parsed.toLocaleString("tr-TR")} ₺`;
                                                            if (col === "HEDEF ÜSTÜ SEFER") {
                                                                style = {
                                                                    color: parsed > 0 ? "#27ae60" : "#e74c3c",
                                                                    fontWeight: "bold",
                                                                };
                                                            }
                                                        }
                                                    }

                                                    if (
                                                        ["ODAK_TALEP", "ODAK_TEDARİK", "ODAK_VERİLEMEYEN"].includes(col)
                                                    ) {
                                                        if (groupIdx === 0) {
                                                            return (
                                                                <td key={colIdx} rowSpan={groupRows.length} style={style}>
                                                                    {displayValue !== undefined && displayValue !== null && displayValue !== "" ? displayValue : 0}
                                                                </td>
                                                            );
                                                        } else {
                                                            return null;
                                                        }
                                                    }

                                                    return (
                                                        <td key={colIdx} style={style}>
                                                            {displayValue !== undefined && displayValue !== null && displayValue !== "" ? displayValue : 0}
                                                        </td>
                                                    );
                                                })}
                                            </tr>
                                        ));
                                    });
                                })()}
                            </tbody>

                        </table>
                    </div>
                ) : (
                    <p className="loading">Yükleniyor...</p>
                )}
            </div>
        </div>
    );
}

export default App;
